    private onCorporationsListEvent(event: CorporationsListEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        const corporations = parser.corporations;

        //console.log('[🏢] Corporations list received:', corporations);

        // 1) cache the latest payload so late subscribers can read it instantly
        (window as any).__olrpCache = {
            ...(window as any).__olrpCache,
            corporations,
            corporationsAt: Date.now(),
        };

        // 2) dispatch to any listeners that are already attached
        window.dispatchEvent(
            new CustomEvent('corporations_list_result', {
                detail: { corporations },
            })
        );
    }

