    private onSlotStateEvent(event: SlotMachineStateEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        // parser.state is already 'IDLE' | 'SPINNING' | 'ENDED'
        const stateStr = (parser.state || 'IDLE') as
            | 'IDLE'
            | 'SPINNING'
            | 'ENDED';

        const detail = {
            state: stateStr,
            reels: typeof parser.reels === 'number' ? parser.reels : 3,
            stops: Array.isArray(parser.stops) ? parser.stops : [],
            win: typeof parser.win === 'number' ? parser.win : 0,
            bet: typeof parser.bet === 'number' ? parser.bet : 0,
            messages: Array.isArray(parser.messages) ? parser.messages : [],
        };

        window.dispatchEvent(new CustomEvent('slotmachine_state', { detail }));
    }

